<style>
:root{--bg1:#080b1e;--bg2:#15103d;--neon:#00f5ff;--gold:#ffd166;--pink:#ff2e88;--green:#5cff9d;--panel:rgba(255,255,255,.09);--stroke:rgba(255,255,255,.16)}
*{box-sizing:border-box} body{min-height:100vh;background:radial-gradient(circle at 10% 10%,rgba(0,245,255,.24),transparent 28%),radial-gradient(circle at 90% 20%,rgba(255,46,136,.22),transparent 30%),linear-gradient(135deg,var(--bg1),var(--bg2));color:#f8fbff;font-family:Inter,system-ui,Segoe UI,sans-serif;overflow-x:hidden}.arena-bg:before{content:"";position:fixed;inset:0;background-image:linear-gradient(rgba(255,255,255,.04) 1px,transparent 1px),linear-gradient(90deg,rgba(255,255,255,.04) 1px,transparent 1px);background-size:42px 42px;mask-image:linear-gradient(to bottom,#000,transparent);pointer-events:none}.navbar{background:rgba(8,11,30,.72);backdrop-filter:blur(14px);border-bottom:1px solid var(--stroke)}.navbar-brand{color:#fff!important;letter-spacing:.4px}.brand-chip{background:linear-gradient(135deg,var(--neon),var(--pink));padding:8px 12px;border-radius:16px;box-shadow:0 0 28px rgba(0,245,255,.35)}.btn{border-radius:16px;font-weight:800;border:0}.btn-primary{background:linear-gradient(135deg,#00b7ff,#6c63ff);box-shadow:0 0 22px rgba(0,183,255,.35)}.btn-success{background:linear-gradient(135deg,#00d084,#67ff9f);color:#062017}.btn-warning{background:linear-gradient(135deg,#ffd166,#ff8a00);color:#201100}.btn-info{background:linear-gradient(135deg,#00f5ff,#7cf6ff);color:#062037}.btn-outline-danger{border:1px solid rgba(255,94,125,.55);color:#ff9ab0;background:rgba(255,70,100,.12)}.hero{position:relative;overflow:hidden;background:linear-gradient(135deg,rgba(0,245,255,.20),rgba(255,46,136,.18));border:1px solid var(--stroke);border-radius:32px;padding:34px;box-shadow:0 30px 80px rgba(0,0,0,.35), inset 0 0 60px rgba(255,255,255,.05)}.hero:after{content:"";position:absolute;right:-80px;top:-90px;width:260px;height:260px;background:radial-gradient(circle,rgba(255,209,102,.36),transparent 65%)}.hero h1{font-weight:1000;letter-spacing:-1px}.score{font-size:46px;font-weight:1000;line-height:1}.xp-label{font-size:12px;text-transform:uppercase;letter-spacing:1.6px;color:#b9c8ff}.card{background:var(--panel);color:#f8fbff;border:1px solid var(--stroke);border-radius:26px;box-shadow:0 20px 55px rgba(0,0,0,.22);backdrop-filter:blur(14px)}.stat-card{transition:.2s}.stat-card:hover{transform:translateY(-4px);box-shadow:0 0 34px rgba(0,245,255,.22)}.student-card{position:relative;overflow:hidden}.student-card:before{content:"";position:absolute;inset:-1px;border-radius:26px;padding:1px;background:linear-gradient(135deg,rgba(0,245,255,.75),rgba(255,46,136,.55),rgba(255,209,102,.55));-webkit-mask:linear-gradient(#000 0 0) content-box,linear-gradient(#000 0 0);-webkit-mask-composite:xor;mask-composite:exclude;pointer-events:none}.avatar{font-size:50px;filter:drop-shadow(0 0 14px rgba(255,255,255,.25))}.rank-badge{display:inline-flex;align-items:center;gap:6px;background:rgba(255,209,102,.16);border:1px solid rgba(255,209,102,.38);color:#ffe7a0;padding:7px 11px;border-radius:999px;font-weight:900}.progress{height:16px;border-radius:999px;background:rgba(255,255,255,.12);overflow:hidden}.progress-bar{background:linear-gradient(90deg,var(--green),var(--neon),var(--gold));box-shadow:0 0 18px rgba(0,245,255,.45)}.form-control,.form-select{background:rgba(255,255,255,.09);border:1px solid rgba(255,255,255,.18);color:#fff;border-radius:16px;padding:12px}.form-control::placeholder{color:#aeb8db}.form-select option{color:#111}.note-pos{background:rgba(92,255,157,.14);border:1px solid rgba(92,255,157,.28)}.note-neg{background:rgba(255,80,120,.14);border:1px solid rgba(255,80,120,.30)}.text-muted{color:#b7c1e6!important}.table{color:#f8fbff}.spark{animation:pulse 1.8s infinite}@keyframes pulse{50%{transform:scale(1.05);filter:drop-shadow(0 0 18px var(--gold))}}canvas{max-height:360px}.mini{font-size:13px;color:#b7c1e6}.battle-title{color:#fff;text-shadow:0 0 24px rgba(0,245,255,.35)}
